-- Abstract aggiornato (21/22)
UPDATE archivio_items SET abstract = 'Un professore giapponese ha inventato un software capace di riconoscere all''istante se un testo e stato copiato oppure no. Tatiana ne parla con i ragazzi in studio..' WHERE id_originale = 38887;
UPDATE archivio_items SET abstract = 'Alcuni ragazzi hanno cercato di raccontare la legalità con versi, pennelli e colori in un concorso organizzato addirittura dalla polizia. I ragazzi raccontano all''inviata del gt come, secondo loro, possiamo diventare dei veri cittadini..' WHERE id_originale = 38888;
UPDATE archivio_items SET abstract = 'Ieri una banda di ragazzini ha distrutto un palazzo a Torino: i dati sono allarmanti, uno studente su tre dichiara di avere subito violenze a scuola. I governo dice basta ai bulli e promette punizioni più severe. I ragazzi intervistati sono d''accordo e propongono alcune soluzioni..' WHERE id_originale = 38889;
UPDATE archivio_items SET abstract = 'Tantissimi ragazzi provenienti da molti paesi d''Europa si sono riuniti per tre giorni a Bruxelles per parlare di mafia e di come combatterla. Hanno manifestato davandi al parlamento europeo per chiedere regole più severe..' WHERE id_originale = 38890;
UPDATE archivio_items SET abstract = 'BRANCAMENTA 2005 (short version) - Una ragazza con un costume verde esce dall''acqua e, completamente bagnata, si sdraia sopra il suo ragazzo che gradisce. L''immagine si sposta poi sul primo piano della modella che beve brancamenta con ghiaccio in un locale. 
Claim: Brancamenta brrrr…
Note: Lo spot è stato girato a Barcellona 
Musica: Eaze Now - Afronaut.' WHERE id_originale = 38892;
UPDATE archivio_items SET abstract = 'MINI MARTINI 2008 (short version) - Primo piano della bella torera (al secolo Leonor Varela, attrice cilena). Si vede poi la bottiglia di Martini su un trono di ghiaccio (con scritta bevi Martini responsabilmente). La torera sfodera la sciabola e riduce la bottiglia intera in una mini-bottiglia di Martini. Claim: ''Mini-Martini la dose perfetta per il tuo Martini''.' WHERE id_originale = 38893;
UPDATE archivio_items SET abstract = 'Sono tanti i vip che hanno aderito a "Convivio", la mostra mercato benefica organizzata per l'' Anlaids Lombardia: tra loro anche Manuela Arcuri che si dichiara entusiasta per l''iniziativa.' WHERE id_originale = 38916;
UPDATE archivio_items SET abstract = 'Operazione della squadra mobile di Milano contro lo spaccio della droga. A Quarto Oggiaro alla periferia di Milano, dopo due anni di indagini, pedinamenti e intercettazioni, sono state arrestate 29 persone legate alla ''ndrangheta calabrese..' WHERE id_originale = 38995;
UPDATE archivio_items SET abstract = 'Riorganizzazione del mondo della scuola. Venticinquemila insegnanti precari e settemila non docenti verranno regolarizzati dal ministero della pubblica istruzione. L''annuncio è stato dato dal ministro Gelmini che ieri ha firmato il decreto di assunzione. Intervento del ministro della p.i. Maria Stella Gelmini che conferma le linee guida del suo predecessore..' WHERE id_originale = 38996;
UPDATE archivio_items SET abstract = 'Per i maturandi, dopo le prove scritte, ora è il momento della prova orale. Dopo giorni di polemiche a causa degli errori provocati dai tecnici che hanno ''ciccato'' gli scritti finalmente arriva il confronto diretto con i professori e qui, si spera, la preparazione degli uni e degli altri non dia adito anessun dubbio. Si tratta dell''ultimo scoglio da superare prima delle sognate vacanze..' WHERE id_originale = 38997;
UPDATE archivio_items SET abstract = 'Un nuovo caso di violenza sessuale ad Ostia (RM). Un clandestino egiziano (45 anni) ha prima drogato e poi violentato una ragazza di 19 anni. L''uomo già con precedenti per spaccio vendeva anche merce contraffatta ed è proprio questo il motivo che ha fatto incontrare i due individui. Lei, dopo due mesi, si è accorta di essere rimasta incinta e ha denunciato l''aggressione..' WHERE id_originale = 38998;
UPDATE archivio_items SET abstract = 'Aggrediti da una banda di ragazzini hanno poi riconosciuto i loro aggressori grazie ad un video che girava in internet. È successo a Milano dove i due aggressori (uno milanese e l''altro marocchino) di 16 anni sono stati fermati dalla polizia e requisita la refurtiva..' WHERE id_originale = 39000;
UPDATE archivio_items SET abstract = 'Buon Compleanno Nelson Mandela. A Londra grande concerto rock per i 90 anni di Nelson Mandela, star internazionali giunte da tutto il mondo per rendere onore al nobel per la pace, per l''Italia ci sarà Zucchero. I proventi di questo concerto saranno devoluti per la lotta contro l''aids in Africa..' WHERE id_originale = 39397;
UPDATE archivio_items SET abstract = 'A Firenze un sacerdote è accusato di abusi su minori. I fatti risalirebbero alla fine degli anni ''90 intanto anche la Chiesa ha aperto un''inchiesta e il parroco è stato rimosso dal mandato. Sembra che tutto si sia svolto durante una vacanza in montagna e, il prete allora 50enne, non mancasse occasione per farsi trovare nudo dai ragazzi..' WHERE id_originale = 39404;
UPDATE archivio_items SET abstract = 'Mentre una voce over maschile ci invita a fidarci della società finanziaria Figenpa , le immagini ci mostrano con uno zoom ininterrotto e l''aiuto della computer grafica l''evoluzione di una giovane coppia: all''inizio studenti fidanzati, poi sposati e sistemati in una casa, infine anziani su una spiaggia insieme alla nipotina. Claim: "Diamo credito al tuo mondo"..' WHERE id_originale = 39415;
UPDATE archivio_items SET abstract = 'FINLANDESI - Un gruppo di finlandesi si vanta di aver inventato la sauna per il corpo e le caramelle Ricola per la gola. Ma ecco intervenire un signore in giacca e cravatta, che rivendica la vera origine delle caramelle Ricola: sono un''invenzione Svizzera. Alla fine lo svizzero e i finlandesi cantano in coro "Ri-co-la!"..' WHERE id_originale = 39419;
UPDATE archivio_items SET abstract = 'Tre ragazzi si trasformano in "iene" per smascherare alcuni coetanei che hanno la cattiva abitudine di inquinare la città, un video dell''Istituto Comprensivo "G. Verga" di Calascibetta (Enna) dal titolo "Basta un gesto". Un bel paese, raccontano i ragazzi, però un po'' sporco... Insomma è un lavoro per il "Trio Merluzzo". Il montaggio del video copia l''ormai mitica trasmissione di Italia1..' WHERE id_originale = 39427;
UPDATE archivio_items SET abstract = 'INDIANO - Lo spot fa parte della campagna "Malati di menti": quattro spot girati filmando sottosopra e animando dei menti umani per farli diventare divertenti personaggi. In questo spot un indiano invoca la pioggia con un canto ritmato, finchè iniziano a piovere sempre più patatine Cipster. Claim: "Crock da shock"..' WHERE id_originale = 39430;
UPDATE archivio_items SET abstract = 'CONFEZIONE 75 CONFETTI - Lui è in ritardo e, quando lei sale in macchina, si fa trovare con lo spazzolino in bocca. La protagonista ha però la soluzione: per una corretta igiene orale, oggi Daygum Protex si presenta con un barattolo da 75 confetti pensato per garantirne sempre la giusta scorta fuori casa, in ufficio così come in auto..' WHERE id_originale = 39450;
UPDATE archivio_items SET abstract = 'GIOIELLI - SAN VALENTINO - Lo spot è tutto costruito sulla testimonial Paris Hilton. Vediamo infatti un montaggio di immagini fisse della modella ai lati delle quali si aprono riquadri di suoi brevi filmati: in tutti, ovviamente, Paris indossa gioielli Bliss. Claim: "Tutto diventa possibile. Anche a San Valentino"..' WHERE id_originale = 39464;
UPDATE archivio_items SET abstract = 'Tragedia a New York. Ieri pomeriggio la bellissima modella kazaka Ruslana Korshunova, 20 anni, è precipitata dal balcone del suo appartamento di New York: le prime indagini parlano di suicidio, ma gli amici della top model dicono che era felice..' WHERE id_originale = 39477;
UPDATE archivio_items SET abstract = 'Allarme malasanità. Giovanni Rosario Calise, un ragazzo di 20 anni, è stato ricoverato in ospedale ad Ischia, in seguito ad un incidente stradale: il giovane rischia di morire perchè in ospedale manca uno strumento per bloccare la sua emorragia. In collegamento telefonico Giovanni Trani (resp.rianimazione osp.Ischia) cerca di spiegare questa strana situazione..' WHERE id_originale = 39478;
UPDATE archivio_items SET abstract = 'Nella notte, nella pineta del Lungomare di Civitavecchia, un migliaio di giovani si sono riuniti per partecipare ad un rave illegale: i carabinieri sono intervenuti e 66 persone sono state denunciate per invasione di terreno pubblico. Il giornalista ricorda che, dietro questi eventi abusivi, si nasconde sempre un grande consumo di droghe spacciate senza problemi..' WHERE id_originale = 39479;
UPDATE archivio_items SET abstract = 'In un luna park americano un ragazzo di 17 anni è morto decapitato da un vagone delle montagne russe. Ogni anno nei parchi divertimento degli Usa ci sono moltissimi morti e feriti, quasi sempre dovuti all''incuranza o disattenzione degli avventori..' WHERE id_originale = 39480;
UPDATE archivio_items SET abstract = 'Padova, uccide il fratello. Francesco Daniele, 27 anni, ha assassinato il fratello Denis, 19 anni. Il movente non è ancora chiaro, l''omicida ha precedenti per spaccio e rapina. La vittima è stata accoltellata più volte e, dai primi accertamenti, non risulterebbe che il fratello maggiore fosse sotto l''effetto di sostanze stupefacenti..' WHERE id_originale = 39484;
UPDATE archivio_items SET abstract = 'È stata affidata alle cure di una psicologa la ragazzina di 12 anni che vendeva le proprie foto osè ai compagni di scuola per comprarsi vestiti ''firmati''. La scrittrice Marida Lombardo Pijola autrice del libro ''ho 12 anni, faccio la cubista, mi chiamano principessa'' racconta di come questo fenomeno sia più dilagante di quel che si pensi..' WHERE id_originale = 39485;
UPDATE archivio_items SET abstract = 'SUOCERA - Lei annuncia al marito che la suocera verrà a fargli visita e lui inizia a fantasticare su come sbarazzarsene. Dopo aver immaginato di soffocarla o legarla ai binari, trova la soluzione più comoda: le darà da bere una Red Bull che la farà volare via, perché "Red Bull ti mette le ali"..' WHERE id_originale = 39511;
UPDATE archivio_items SET abstract = 'SONO FINTE - Un ragazzo sale su un tram dove viaggiano tre ragazze: due hanno un seno normale, la terza ce l''ha prorompente. Il ragazzo ingoia una mentina Frisk e poi esclama ad alta voce "Sono finte!", riferendosi ovviamente alle tette. La ragazza incrocia le braccia vergognosa e scocciata, mentre le altre due la guardano assaporando la loro rivincita. Claim: "Non temere di aprir bocca"..' WHERE id_originale = 39527;
UPDATE archivio_items SET abstract = 'L''attuale incubo di Londra, in questi giorni, arriva da un serial killer che sembra prediligere vittime giovanissime. In quest''ultima settimana sono già tre i morti trovati orrendamente massacrati. In totale, dall''inizio dell''anno sono già 18 le vittime, quasi tutti minorenni e tutti uccisi con tantissime coltellate..' WHERE id_originale = 39539;
UPDATE archivio_items SET abstract = 'Strip tease in cambio di ricariche telefoniche. Il giro è stato scoperto su un sito gestito a Napoli, e ci sarebbe persino un tariffario per le sexy esibizioni delle cam girl. Annunci on line, spettacoli in cam e ricarica sul cellulare. Naturalmente le partecipanti di questo scambio sono tutte ragazze giovanissime..' WHERE id_originale = 39542;
UPDATE archivio_items SET abstract = 'Nel mondo sono ancora in tanti a curarsi con le erbe. In diverse zone dell''Africa questo è ancora l''unico modo per curarsi da tante malattie. lìItalia è in primo piano per la cooperazione in questo settore col progetto ''un orto botanico in ogni villaggio''..' WHERE id_originale = 39548;
UPDATE archivio_items SET abstract = 'L''associazione Amici dell''Università di Torino ha lanciato un invito ai neo laureati : 3000 l''hanno accolto sugli 11 dell''ultima tornata. Una grande serata di musica e incontri. Negli ultimi anni le donne battono gli uomini: 65 contro 35 ogni 100 laureati. 75 studenti su 100 arrivano da famiglie i cui genitori non sono laureati..' WHERE id_originale = 39582;
UPDATE archivio_items SET abstract = 'Dopo le molte polemiche suscitato dal caso Eluana Englaro (la ragazza in coma da 16 anni a cui i giudici hanno permesso di staccare la spina) c''è invece chi ha un''altra visione della vita. È il caso di Andrea, il ragazzo di 16 anni, disabile al 100% che non riesce a parlare e a vedere. Grazie ad un progetto sperimentale è riuscito a comunicare al medico la propria gioia di vivere..' WHERE id_originale = 39608;
UPDATE archivio_items SET abstract = 'Il Papa in viaggio verso l''Australia per la Giornata Mondiale della Gioventù. E'' il viaggio più lungo di Benedetto XVI°, ad attenderlo una chiesa cattolica alle prese con molti problemi come gli scandali sessuali, ''mancato rispetto dell''ambiente e, per quanto riguarda gli scandali pedofilia sono incompatibili con il sacerdozio'' questi i temi toccati durante il volo dal pontefice..' WHERE id_originale = 39634;
UPDATE archivio_items SET abstract = '(sito centrodiascolto.it) - L''accusa nei loro confronti è di violenza di gruppo nei confronti di due loro coetanee. I quattro, due 16enni e due 17enni, avrebbero abusato sessualmente di una delle due e avrebbero provato a fare la stessa cosa con la seconda. Due degli indagati sono stati portati nel carcere minorile di Benevento, gli altri due in quello di Napoli.' WHERE id_originale = 39655;
UPDATE archivio_items SET abstract = 'Sentenza storica nei confronti delo Stato Italiano che è stato condannato a risarcire un giovane al quale era stata tolta la patente perché alla visita militare aveva dichiarato la propria omosessualità. La sentenza del tribunale stima in 100.000€ il risarcimento per l''umiliazione e la discriminazione sessuale a favore di Danilo Giuffrida, siciliano di 26 anni. Il movimento gay: esulta!..' WHERE id_originale = 39675;
UPDATE archivio_items SET abstract = 'Emergenza criminalità in Gran Bretagna: 60 casi al giorno di crimini e minacce con coltelli, il governo annuncia misure straordinarie. Altri due giovani morti l''altra notte sempre accoltellati, 20.000 le aggressioni nell''ultimo anno con questo tipo di arma. Il governo sembra indirizzato nel mettere il coprifuoco agli under 18 in alcune zone a rischio della città.' WHERE id_originale = 39680;
UPDATE archivio_items SET abstract = 'Alcuni ragazzini di Campobasso riservavano un trattamento disumano ad un loro coetaneo disabile: i video delle loro sevizie finivano poi su internet. I ragazzi sono stati individuati e fermati dopo che il fratello della vittima aveva denunciato tutto alla polizia.' WHERE id_originale = 39696;
UPDATE archivio_items SET abstract = 'Fuggi-fuggi dalla discoteca, 12 morti a Città del Messico. Una festa di studenti si è trasformata in un incubo mortale in seguito ad un blitz della polizia nel locale perché è vietato il consumo di alcol per i minorenni. 9 i morti tra i giovni e gli studenti che stavano festeggiando la fine dell''anno scolastico..' WHERE id_originale = 39706;
UPDATE archivio_items SET abstract = 'È morto fulminato mentre puliva il trattore del nonno. È successo a Gottolengo (BS) la vittima è un ragazzo di 14 anni colpito da una scarica elettrica causata da un cavo elettrico dell''idropulitrice che, staccatosi, è finito in acqua dove il ragazzo aveva inavvertitamente messo i piedi. Era una promessa del rugby..' WHERE id_originale = 39723;
UPDATE archivio_items SET abstract = '(centrodiascolto.it) - Anche la musica si mobilita contro la camorra. Il rapper Lucariello presenta un videoclip prodotto da MTV Italia contro tutte le mafie dal titolo Cappotto di Legno. Al videoclip che è anche sottotitolato, ha partecipato lo scrittore Roberto Saviano come supervisore..' WHERE id_originale = 39725;
UPDATE archivio_items SET abstract = 'Sembra una storia ispirata al film ''Juno'', ma questo patto per la gravidanza ha sicuramente choccato la società americana. Infatti 17 adolescenti hanno deciso, tutte insieme, di rimanere incinta e di portare a termine la gravidanza, senza chiedere il consenso né ai genitori né a prefessori o assistenti. Tutte le ragazze hanno deciso di avere un bambino prima di compiere i 16 anni (detto-fatto)..' WHERE id_originale = 39728;
UPDATE archivio_items SET abstract = 'Padova, ingaggiati due poliziotti romeni. Il Comune di Padova ha ingaggiato due poliziotti romeni per fronteggiare la criminalità dell''est europa che, dopo l''apertura delle frontiere si è fatta più aggressiva. Non è una novità per la città infatti Padova ha già sperimentato vigili cinesi, centro e nordafricani, tutti impegnati nei quartieri a rischio..' WHERE id_originale = 39732;
UPDATE archivio_items SET abstract = 'I quartieri della paura, Padova. Paura degli abitanti e commercianti della zona presso la stazione. E per questo vedono con favore la presenza dei militari per le strade. Ricordo che questa eventualità fa parte del pacchetto sicurezza presentato dal nuovo governo. Testimonianze di alcuni residenti tutti concordi nel dire che, in città, non si può più vivere sereni e tranquilli..' WHERE id_originale = 39733;
UPDATE archivio_items SET abstract = 'Rom aggredito a Milano accusa la polizia. Si tratta del padre della bambina, già aggredita nei giorni scorsi; l''uomo accusa due agenti della Polfer di aver aggredito lui e, nei giorni scorsi, la figlia di 12 anni e il fratellino di 11. La polizia afferma che l''uomo era stato invitato, senza violenza, ad andarsene dalìaccampamento abusivo dove abita..' WHERE id_originale = 39735;
UPDATE archivio_items SET abstract = 'Per la giornata dello skateboard, a Milano e non solo, il popolo dello skate ha invaso la città con le sue piroette. Grande partecipazione dei giovanissimi che amano questo sport. Intervista a Davide Martinazzo (organizzatore go skateboarding day) che parla di come gli skaters amino riprendersi gli spazi urbani altrimenti dedicati solo al traffico e al lavoro..' WHERE id_originale = 39740;
UPDATE archivio_items SET abstract = 'Torino, ubriaco uccide un motociclista. Un rumeno ubriaco di 56 anni, con un tasso alcolemico 4 volte superiore al normale, ha travolto e ucciso con la sua auto un motociclista. Il rumeno è stato arrestato e rischia una condanna tra i 3 e i 10 anni di carcere, come previsto dalle nuove norme del pacchetto sicurezza. La vittima è un impiegato di 39 anni..' WHERE id_originale = 39741;
UPDATE archivio_items SET abstract = 'Maestra di Genova chiede due anni di proroga prima di andare in pensione. Sono i suoi allievi e i loro genitori a chiedere al ministro di concedere alla loro insegnante, 70enne, altri due anni per condurli fino all''esame di quinta. Lo chiedono anche i genitori dei bambini e la stessa insegnante..' WHERE id_originale = 39745;
UPDATE archivio_items SET abstract = 'OROLOGI - Una raggio di luce avanza pian piano verso lo schermo. Si scopre che la fonte è un orologio solo quando Francesca Lodo vi passa per un momento la mano sopra. Quando la toglie torna la luce. Claim: "Brosway. Made of light". Musica: "Skin" di Il Deboscio..' WHERE id_originale = 39754;
UPDATE archivio_items SET abstract = 'BLACK XS - Lui a petto nudo con varie catenine al collo, lei vestita di nero, giovani, belli. Si guardano, sembrano sfidarsi a sguardi, sorridono. Sono i testimonial di BlackXs, la nuova fragranza di Paco Rabanne, per uomo e donna. La pronuncia in inglese di "Xs" equivale ad "Excess", cioè eccesso..' WHERE id_originale = 39755;
UPDATE archivio_items SET abstract = 'PANINO - Lui sta per mordere un panino, lei lo invita a farlo in modo provocante. Quando l''immagine si allarga scopriamo che i due sono a letto e che il panino in realtà è il piede di lei. Claim: "Shock your time". Musica originale, fotografia e scenografia virate sul grigio a richiamare il metallo dell''orologio Chronotech..' WHERE id_originale = 39756;
UPDATE archivio_items SET abstract = 'PISTOLA - Spot realizzato in computer grafica per esaltare la velocità del processore della consolle Sony. Un cowboy spara addosso a un ragazzo, che evita tutte le pallottole. La voce over spiega: "Un processore per stare sempre un passo avanti". Il cowboy punta verso noi spettatori e spara: dall''esplosione si materializza il logo Playstation 3, con il claim "This is living"..' WHERE id_originale = 39759;
UPDATE archivio_items SET abstract = 'UNCHARTED - Lo spot fa vedere alcune immagini del videogioco di azione/avventura "Uncharted", in vendita assieme alla consolle. Nelle sequenze tratte dal gioco si vedono esplosioni, sparatorie, salti nel vuoto. La voce over commenta in chiusura: "Il divertimento come non lo hai mai provato prima", mentre compare il logo della PS3 e il claim "This is living"..' WHERE id_originale = 39762;
UPDATE archivio_items SET abstract = 'FAMILY - BIMBO - Nello spot vediamo una classica famiglia con padre, madre, figlia e neonato, tutti interpretati da Ezio Greggio. Dopo aver elencato i vantaggi dell''offerta Tiscali Family, pensata per chi ha figli (telefonate Adsl senza limiti scontate del 25%), nel finale Greggio "papà" si becca nell''occhio il ciuccio sputato dal neonato..' WHERE id_originale = 39771;
UPDATE archivio_items SET abstract = 'SENZA VOLTO - Ragazzi e ragazze, alcuni in posa, altri stanno facendo sport: tutti indossano delle t-shirt tirate a coprire il volto fino alla fronte. Claim: "Kokse. Numero uno nelle t-shirt da personalizzare"..' WHERE id_originale = 39798;
UPDATE archivio_items SET abstract = 'SCACCHI - Ale e Franz stanno giocando a scacchi. Ale è continuamente al cellulare con un operatore di Conto Arancio: si sentono ogni giorno, spiega, perché i suoi risparmi crescono quotidianamente. Franz deve muovere, ma è completamente ingessato: comunica le coordinate della sua mossa al pappagallo, ma questi si limita a ripeterle, senza muovere il pezzo. La musica è "Clint Eastwood" dei Gorillaz..' WHERE id_originale = 39804;
UPDATE archivio_items SET abstract = 'NOI WIND 4000 SMS - I condor Giovanni e Giacomo infastidiscono Aldo, appollaiato in mezzo a loro, strappandogli le penne per scrivere al licaone. Aldo li invita a scrivere un sms anziché un''obsoleta lettera, così lo lasceranno in pace: con la promozione Noi Wind hanno 4000 sms gratis al mese verso tutti i telefonini Wind..' WHERE id_originale = 39810;
UPDATE archivio_items SET abstract = 'ALICE SKY - Papà Abadantuomo sta per entrare in salotto quando vede sul divano la figlia, insieme ad un ragazzo. "Uno sconosciuto, con mia figlia, sul mio divano!" commenta spazientito. La moglie lo calma, spiegandogli che stanno guardando la tv: grazie ad Alice possono avere tutta l''offerta Sky. Abadantuomo non è convinto, anzi: con tutta questa offerta il pretendente non si schioderà più!..' WHERE id_originale = 39812;
UPDATE archivio_items SET abstract = 'I450 IMMAGINA - "Immagina di immaginare tutto e di poterlo condividere, filmare, suonare…". L''accattivante prospettiva enunciata dalla voce over accompagna le immagini di un giovane: intorno a lui le pareti si colorano di scritte e disegni che raffigurano le infinite potenzialità del Samsung I450,  definito dal claim: "Multipotente, onnimediale"..' WHERE id_originale = 39813;
UPDATE archivio_items SET abstract = 'DOPPIA RICARICA - EL CONDOR PASA - I condor Giovanni e Giacomo, appollaiati su un ramo sospeso su uno strapiombo, stanno litigando per il posto. Giovanni chiama in aiuto suo cugino, "el condor pasa", che però al suo arrivo fa crollare il ramo per il peso eccessivo della "doppia ricarica". Giacomo, rimasto incolume, prende in giro i due: "Ehi, doppio cretino, perché non ti chiami a tua sorella?"..' WHERE id_originale = 39825;
UPDATE archivio_items SET abstract = 'Strettamente in linea con la campagna stampa, lo spot vede, in un delicato gioco di inquadrature accompagnato da un tango suadente, Elena Sofia Ricci invitare delicatamente il pubblico femminile a scoprire il seno. Voce fuoricampo: ''Europa Donna, movimento di opinione europeo per la lotta al tumore del seno''.' WHERE id_originale = 39835;
UPDATE archivio_items SET abstract = 'RAGNO - Vediamo il volto di una ragazza su un paesaggio lunare. Qualche inquadratura dopo ci rendiamo conto che la ragazza ha la parte inferiore del corpo come un ragno. In chiusura l''immagine viene racchiusa nel logo di Mtv..' WHERE id_originale = 39842;
UPDATE archivio_items SET abstract = 'Due ragazzine rom che non sapevano nuotare sono state travolte dalle onde e dalla corrente che le ha portate al largo, e sono annegate sotto lo sguardo di decine di bagnanti che hanno assistito impotenti all''accaduto. Inutile l''intervento dei vigili del fuoco e del 118..' WHERE id_originale = 39846;
UPDATE archivio_items SET abstract = 'Il governo inglese prova a contrastare l''abitudine al bere dei cittadini vietando i bicchieri extra-large nei pub: sono necessari bicchieri più piccoli e meno capienti per il consumatore che ha bisogno così di più tempo, più fatica e più soldi per perdere il controllo..' WHERE id_originale = 39849;
UPDATE archivio_items SET abstract = 'Ragazza inglese in gita scolastica a Venezia cade dal davanzale della sua stanza d''albergo sul quale era seduta. Si era sporta per prendere un accendino dalla compagna nella stanza accanto quando il davanzale ha ceduto e la ragazza è caduta da otto metri d''altezza; è grave..' WHERE id_originale = 39850;
UPDATE archivio_items SET abstract = 'Un motociclista è stato travolto e ucciso da un albanese con una quantità di alcol nel sangue sei volte superiore alla norma e un pensionato è stato investito da un macedone ubriaco..' WHERE id_originale = 39851;
UPDATE archivio_items SET abstract = 'Moldavo in fuga dalla polizia provoca un incidente e uccide il giovane Rocco. I famigliari della vittima e la sua migliore amica parlano senza rabbia ma chiedono che giustizia sia fatta, che il giovane paghi la pena senza sconti e che la morte di Rocco non venga strumentalizzata in nessun modo..' WHERE id_originale = 39852;
UPDATE archivio_items SET abstract = 'A Londra ennesima aggressione con coltello di un ragazzo diciassettenne ad opera di coetanei. Sono così salite a ventuno le vittime per aggressioni nell''ultimo anno nella capitale inglese..' WHERE id_originale = 39853;
UPDATE archivio_items SET abstract = 'Tra le storie che coinvolgono gli immigrati clandestini ha finale positivo quella di una ragazza diciannovenne che ha partorito il suo bambino; diversamente è andata invece per due bimbi morti durante la traversata tra le braccia del padre. Intanto il ministro Frattini sostiene che ci sono magistrati compiacenti verso gli scafisti e quindi non applichino le sanzioni adatte.' WHERE id_originale = 39879;
UPDATE archivio_items SET abstract = 'Un giovanissimo rom è stato salvato dal linciaggio dopo il tentativo di furto in un appartamento ad Alessandria. È stato arrestato e ora si trova in carcere..' WHERE id_originale = 39888;
UPDATE archivio_items SET abstract = 'Retata dei carabinieri a Torino per tentare di fermare gli spacciatori dell''eroina killer che in pochi giorni avrebbe fatto ben 4 vittime. Alcuni spacciatori sono stati sorpresi a tagliare la droga in riva al fiume, per terra, come sostiene il cap. Isacchini. Le forze dell''ordine hanno poi sequestrato molte dosi per analizzarle..' WHERE id_originale = 39912;
UPDATE archivio_items SET abstract = 'Giovani armati di coltello e manganello telescopico si sono affrontati in piazza Vittorio a Torino: la rissa, generata da insulti e sguardi di troppo si è svolta in due riprese ed è stata fermata dall''intervento delle forze dell''ordine che hanno denunciato otto ragazzi..' WHERE id_originale = 39935;
UPDATE archivio_items SET abstract = 'Blitz dei carabinieri nella provincia di Cosenza per fermare un traffico di anabolizzanti che coinvolgeva numerose palestre della zona. I farmaci venivano comprati all''estero per poi essere smistati nelle palestre; arrestati tre uomini..' WHERE id_originale = 39945;
UPDATE archivio_items SET abstract = 'Giovane dopo la festa di un amico si accorge di aver bevuto troppo, decide di dormire in macchina e viene multato dagli agenti per guida in stato di ebrezza, ma secondo le forze dell''ordine i fatti si sono svolti diversamente: il giovane avrebbe guidato l''auto fino al luogo dov''era parcheggiata dopo aver urtato un ostacolo. La realtà dei fatti verrà stabilita da un tribunale..' WHERE id_originale = 39946;
UPDATE archivio_items SET abstract = 'La strada che congiunge Roma a Ostia era diventata sede di corse clandestine, ma le proteste dei residenti che si lamentavano per l''insostenibile baccano hanno fatto scattare i controlli delle forze dell''ordine culminati in una retata..' WHERE id_originale = 39947;
UPDATE archivio_items SET abstract = 'Parla il fidanzato di Nicole, uccisa dall''ecstasy a 16 anni, che la difende, sostenendo non si meritasse quella morte e scagliandosi contro i rave abusivi non controllati dalla polizia. I funerali della ragazza potrebbero tenersi venerdì..' WHERE id_originale = 39948;
UPDATE archivio_items SET abstract = 'Silvio Cogno, organizzatore, parla della singolare competizione che si è svolta a Novello tra i paesi del Barolo che si sono sfidati in numerose discipline e dalle quali è risultato vincitrice Monforte d''Alba..' WHERE id_originale = 39949;
UPDATE archivio_items SET abstract = 'A S. Anna di Monteu Roero si svolge la festa dell''Arneis, vino tipico del roero che ha acquistato fama internazionale..' WHERE id_originale = 39950;
UPDATE archivio_items SET abstract = 'Al politecnico di Torino ad una ragazza è stato impedito di dare un''esame universitario perché lavoratrice e quindi impossibilitata a seguire personalmente il corso. Il vice direttore del politecnico Chiana spera che la ragazza riesca a laurearsi, aiutandosi anche con i corsi in teledidattica..' WHERE id_originale = 39953;
UPDATE archivio_items SET abstract = 'Da quest''anno tornano gli esami di riparazione che costringeranno tutti gli studenti con debiti a passare l''estate sui libri. Il ministro dell''istruzione Gelmini sostiene sia importante per permettere alla scuola di acquistare credibilità. La materia che piace meno è sicuramente la matematica, poi lingua straniera, discipline scientifiche e italiano..' WHERE id_originale = 39956;
UPDATE archivio_items SET abstract = 'I pirati della strada sono sempre più spesso causa di incidenti mortali dovuti al loro uso di alcol o droga, ma tre su quattro vengono immediatamente arrestati e incarcerati dalle forze dell''ordine..' WHERE id_originale = 39957;
UPDATE archivio_items SET abstract = 'I rave party sono sempre più diffusi e durante essi la droga circola liberamente tra i giovani: 9 su 10 ne fanno uso per poter affrontare l''intera notte, o tutto il giorno, ballando ai ritmi della musica techno e house..' WHERE id_originale = 39959;
UPDATE archivio_items SET abstract = 'Il giovane ubriaco che aveva investito una coppia di fidanzati a Salerno, provocando la morte del ragazzo e il ferimento della donna, ora rischia di tornare in libertà. Il fratello della vittima chiede giustizia e che il colpevole sia tenuto in carcere perché non commetta un''altra volta lo stesso crimine..' WHERE id_originale = 39960;
UPDATE archivio_items SET abstract = 'La signora Maccarini, mamma di una ragazza promessa dello sci stroncata dall''ecstasy telefona ai genitori di Nicole, uccisa da una pasticca, offrendo il suo conforto. La donna si dispera perché lo spacciatore che ha venduto la droga alla figlia è già in libertà e sostiene sia necessario fermare questa "epidemia della droga" con più controlli..' WHERE id_originale = 39961;
UPDATE archivio_items SET abstract = 'Giorgia racconta la sua esperienza: dopo aver assunto ecstasy una sera in discoteca è andata in cirrosi epatica e in coma; ha subito un trapianto di fegato che l''ha salvata. Ora giorgia racconta la sua esperienza nelle scuole e partecipa ad attività di prevenzione.' WHERE id_originale = 39968;
UPDATE archivio_items SET abstract = 'Nel bresciano è stata sequestrata una nuova droga, la Cristal Meth, una metanfetamina con effetti devastanti sul cervello. Il comandante propato sostiene come l''assunzione con l''alcol di questa droga provochi effetti molto gravi anche sul fegato..' WHERE id_originale = 39970;
UPDATE archivio_items SET abstract = 'Negli Stati Uniti per anni la droga è riuscita ad arrivare fino in Messico grazie ad un sistema di trasporto tramite piccoli sommergibili che viaggiavano a pelo d''acqua durante la notte in modo da non poter essere localizzati dai sonar e dai radar. Ora la marina statunitense ha trovato il modo di localizzarli e di impedire questo massiccio traffico..' WHERE id_originale = 39973;
UPDATE archivio_items SET abstract = 'Due ragazzine rom muoiono annegate dalle alte aonde e dalla forte corrente. I bagnanti riescono a salvare due delle quattro bimbe che si erano buttate in mare ma inutili i soccorsi per le altre due. I corpicini morti rimangono sulla spiaggia coperti da teli da mare fino all''arrivo delle bare di legno.' WHERE id_originale = 39974;
UPDATE archivio_items SET abstract = 'Ragazzi protagonisti assoluti del Giffoni Film Festival che anche quest''anno propone grandi anteprime di film per ragazzi e famiglie. Michela Coppa sostiene sia un''ottima occasione che permette ai giovani di incontrare attori e registi italiani e internazionali tra cui una bambina americana candidata all''oscar..' WHERE id_originale = 39976;
UPDATE archivio_items SET abstract = 'L''università del Piemonte Orientale è una delle migliori: importante offerta formativa e conti in regola. Il problema è il sottofinanziamento e le norme del governo che potrebbero sfavorire questa università.' WHERE id_originale = 39996;
UPDATE archivio_items SET abstract = 'A Venezia si cercano gli spacciatori che hanno venduto l''ecstasy che ha ucciso una ragazza e presto comincerà l''autopsia sul corpo della stessa per capire come mai lei è morta mentre le sue amiche che avevano assunto come lei la droga, si sono salvate..' WHERE id_originale = 40024;
UPDATE archivio_items SET abstract = 'Blitz dei carabinieri ad un rave party nei dintorni di Verona: 8 ragazzi sono stati arrestati per detenzione e spaccio di droga. Sono state sequestrate dai carabinieri: eroina, cocaina e pastiglie di lsd.' WHERE id_originale = 40041;
UPDATE archivio_items SET abstract = 'Lorena, la quattordicenne violentata e uccisa ad aprile da tre minorenni, non era incinta: i ragazzi avevano detto di aver compiuto il delitto spinti dalla gravidanza dichiarata dalla ragazza, ma la perizia medica ha accertato dopo due mesi che la giovane non era incinta..' WHERE id_originale = 40081;
UPDATE archivio_items SET abstract = 'Nel mantovano un pirata della strada ubriaco travolge due ciclisti e ne uccide uno di loro.' WHERE id_originale = 40093;
UPDATE archivio_items SET abstract = 'Matteo Cambi, l''inventore della marca GURU che era finito in carcere per bancarotta fraudolenta, sta malissimo a causa dell''astinenza da cocaina. In un''intervista ad un giornale ammette di essere diventato un tossicodipendente a causa del successo improvviso che lo ha travolto: a causa della droga ha distrutto il suo impero e ora si dice pronto ad entrare in comunità.' WHERE id_originale = 40103;
UPDATE archivio_items SET abstract = 'Grazie ad una telecamera nascosta del giornalista di studio aperto presente ad un rave in provincia di Novara la polizia ha potuto arrestare due spacciatori. Nel video il giornalista chiede in giro della droga, ma lui vuole la ketamina e viene accompagnato da una ragazza minorenne che lo rifornirà a dovere.' WHERE id_originale = 40133;
UPDATE archivio_items SET abstract = 'Continuano le ricerche di Riccardo Rizzoglio, il 20enne di Castiglione Tinella (CN) che dopo aver partecipato ad una festa di coscritti ha bocciato con l''auto del padre abbandonandola sul ciglio della strada e facendo sparire le proprie tracce. I genitori lanciano l''ennesimo appello (purtroppo la soluzione del caso è vicina ed è tragica)' WHERE id_originale = 40141;
UPDATE archivio_items SET abstract = 'Abbronzatura artificiale vietata per i giovanissimi di Francia e Germania: i rischi sono i tumori della pelle. Anche i medici italiani inizianon a lanciare l''allarme. La dott.ssa Desanka Raskovic, Istituto Dermopatico dell''Immacolata, afferma che il danno provocato alle cellule in giovane età, si accumula nel tempo e può portare da adulto a forme tumorali della pelle anche gravi.' WHERE id_originale = 40192;
UPDATE archivio_items SET abstract = 'A Bari un gruppo di baby estorsori hanno costretto un 13enne a consegnargli 4.000€, soldi che la vittima sottraeva ai genitori. Il gruppetto era composto da un 16enne e due 18enni tre piccoli, ma poi neanche tanto, criminali.' WHERE id_originale = 40198;
UPDATE archivio_items SET abstract = 'Luca e Davide sono due ragazzi romagnoli che nel 2005, in vacanza, vennero fermati in Grecia e trovati in possesso di pochi grammi di hascisc (per l''esattezza 21). Adesso la Grecia ne chiede l''estradizione e i due ragazzi rischiano 10 anni di galera; il loro paese, Sant''Argangelo di Romagna si è mobilitato per loro affinchè Italia e Grecia trovino un accordo per evitarne la carcerazione.' WHERE id_originale = 40247;